patch:
--- a/alu.sv
+++ b/alu.sv
@@ -1,18 +1,18 @@
 module alu_16bit (
   input [15:0] operand_a, operand_b,
   input [2:0] opcode,
   output reg [15:0] result
 );

-  always @(operand_a) begin
+  always @(*) begin
     case (opcode)
       3'b000: result = operand_a + operand_b;
       3'b001: result = operand_a - operand_b;
       3'b010: result = operand_a & operand_b;
       3'b011: result = operand_a | operand_b;
       3'b100: result = operand_a ^ operand_b;
       3'b101: result = ~operand_a;
       default: result = 16'h0;
     endcase
   end
 endmodule

before_code:
module alu_16bit (
  input [15:0] operand_a, operand_b,
  input [2:0] opcode,
  output reg [15:0] result
);

  always @(operand_a) begin
    case (opcode)
      3'b000: result = operand_a + operand_b;
      3'b001: result = operand_a - operand_b;
      3'b010: result = operand_a & operand_b;
      3'b011: result = operand_a | operand_b;
      3'b100: result = operand_a ^ operand_b;
      3'b101: result = ~operand_a;
      default: result = 16'h0;
    endcase
  end
endmodule

after_code:
module alu_16bit (
  input [15:0] operand_a, operand_b,
  input [2:0] opcode,
  output reg [15:0] result
);

  always @(*) begin
    case (opcode)
      3'b000: result = operand_a + operand_b;
      3'b001: result = operand_a - operand_b;
      3'b010: result = operand_a & operand_b;
      3'b011: result = operand_a | operand_b;
      3'b100: result = operand_a ^ operand_b;
      3'b101: result = ~operand_a;
      default: result = 16'h0;
    endcase
  end
endmodule
